// Parse the Stripe event. create-checkout.js stores per-plan metadata:
// plan_1_prison / plan_1_state / plan_1_mobile / plan_1_interval, plus bundle, plan_count.
const raw = $input.first().json;
const body = raw.body || raw;
const event = body && body.type ? body : (body.event || body);
const eventType = event.type || raw.type || 'unknown';
const obj = (event.data && event.data.object) ? event.data.object : (event.object || {});
const md = obj.metadata || {};

function pick() {
  for (const k of arguments) {
    if (md[k] !== undefined && md[k] !== '') return md[k];
  }
  return '';
}

const mobile_number = String(pick('plan_1_mobile', 'mobile_number', 'mobile'))
  .replace(/[^0-9]/g, '')
  .replace(/^61/, '0')
  .slice(-10);

const out = {
  event_type: eventType,
  prison_name: pick('plan_1_prison', 'prison_name'),
  prison_state: String(pick('plan_1_state', 'prison_state')).toLowerCase(),
  plan_interval: String(pick('plan_1_interval', 'plan_interval')).toLowerCase(),
  mobile_number: mobile_number,
  bundle: String(pick('bundle')).toLowerCase() === 'true',
  plan_count: Number(pick('plan_count') || 1),
  stripe_customer_id: obj.customer || pick('stripe_customer_id') || '',
  stripe_subscription_id: obj.subscription || pick('stripe_subscription_id') || '',
  customer_email: (obj.customer_details && obj.customer_details.email) || obj.customer_email || ''
};

return [{ json: out }];

// Prison DID Lookup - source of truth: Prisoncall_DID_Provisioning_Table / Prison_DID_Lookup_v3_0.csv.
// Town strings in primary/fallback_* are the EXACT strings passed to the VoipLine search endpoint.
const CSV = `prison_name,prison_state,primary,primary_state,fallback_1,fallback_1_state,fallback_2,fallback_2_state,fallback_3,fallback_3_state
