// Primary-exchange dial prefixes (area code + exchange, no spaces) for the Request Numbers flow.
// OUTSTANDING per handoff: postcodes still to be added for all exchanges.
const townPrefix = {
  'Lara': '034224', 'Werribee': '038000', 'Melbourne': '037057', 'Beechworth': '034714',
  'Wangaratta': '035721', 'Chiltern': '035726', 'Geelong': '034232', 'Sale': '034159',
  'Traralgon': '035176', 'Shepparton': '034804', 'Ararat': '034328', 'Ballarat': '035300',
  'Horsham': '034336', 'Beaufort': '034329', 'Castlemaine': '034430', 'Bendigo': '034428',
  'Penrith': '024702', 'Blacktown': '028609', 'Sydney': '029178', 'Lismore': '025624',
  'Grafton': '026632', 'Coffs Harbour': '025603', 'Bathurst': '025340', 'Orange': '026325',
  'Lithgow': '025322', 'Broken Hill': '028013', 'Dubbo': '025836', 'Cessnock': '024012',
  'Maitland': '024072', 'Newcastle': '024940', 'Cooma': '026422', 'Goulburn': '023813',
  'Bega': '026492', 'Glen Innes': '025768', 'Armidale': '026714', 'Tamworth': '025781',
  'Bowral': '024879', 'Gosford': '024313', 'Young': '026382', 'Kempsey': '025504',
  'Port Macquarie': '026583', 'Kiama': '024216', 'Wollongong': '024217', 'Muswellbrook': '026535',
  'Wagga Wagga': '', 'Albury - Wodonga': '', 'Tooma': '', 'Talbingo': ''
};

const d = $json;
const lines = CSV.trim().split('\n');
const headers = lines[0].split(',');
const rows = lines.slice(1).map((l) => {
  const c = l.split(',');
  const o = {};
  headers.forEach((h, i) => { o[h] = (c[i] || '').trim(); });
  return o;
});

const norm = (s) => String(s || '').toLowerCase().replace(/[^a-z0-9]/g, '');
const target = norm(d.prison_name);
let row = rows.find((r) => r.prison_name.toLowerCase() === String(d.prison_name).toLowerCase());
if (!row) row = rows.find((r) => norm(r.prison_name) === target);
if (!row) throw new Error('Prison not found in DID lookup table: ' + d.prison_name);

const exchanges = [row.primary, row.fallback_1, row.fallback_2, row.fallback_3]
  .filter((t) => t && t.length)
  .map((t) => ({ town: t, prefix: townPrefix[t] || '' }));

return [{
  json: {
    ...d,
    exchanges: exchanges,
    request_prefix: (exchanges[0] && exchanges[0].prefix) || '',
    request_postcode: ''
  }
}];

// Order a DID from VoipLine following the EXACT documented sequence, attempting
// primary -> fallback_1 -> fallback_2 -> fallback_3 in order. ALL VoipLine calls go
// through the Cloudflare Worker proxy. 3CX is NOT touched here.
//
// NOTE: VoipLine response field names (id / number / order_id) are mapped defensively
// below and must be confirmed against live responses at Phase 1C integration.
const helpers = this.helpers;
const PROXY_URL = 'https://workers.prisoncall.com.au/voipline-proxy';
const SECRET = $env.VOIPLINE_PROXY_SECRET;

async function voipline(path, method, jsonBody) {
  const opts = {
    method: 'POST',
    url: PROXY_URL,
    headers: {
      'X-Proxy-Secret': SECRET,
      'X-VoipLine-Path': path,
      'X-VoipLine-Method': method,
      'Content-Type': 'application/json'
    },
    json: true
  };
  if ((method === 'POST' || method === 'PUT')) opts.body = jsonBody || {};
  return await helpers.httpRequest(opts);
}

const asArray = (r) => Array.isArray(r) ? r : (r && (r.data || r.results || r.numbers || r.items)) || [];

const d = $json;
let result = null;
const attempts = [];

for (const ex of d.exchanges) {
  try {
    const search = await voipline('/api/customer/pricings/countries/13?query=' + encodeURIComponent(ex.town), 'GET');
    const pricings = asArray(search);
    for (const pricing of pricings) {
      const pricingId = pricing.id || pricing.pricing_id;
      if (!pricingId) continue;
      // (optional) ordering restrictions check
      try { await voipline('/api/customer/pricings/' + pricingId + '/ordering-restrictions', 'GET'); } catch (e) {}
      const numbersResp = await voipline('/api/customer/numbers/pricing/' + pricingId, 'GET');
      const numbers = asArray(numbersResp);
      if (!numbers.length) { attempts.push({ town: ex.town, pricingId, stock: 0 }); continue; }
      const first = numbers[0];
      const numberId = first.id || first.number_id;
      const orderId = numbersResp.order_id || numbersResp.orderId || first.order_id;
      if (!orderId || !numberId) { attempts.push({ town: ex.town, pricingId, note: 'missing order/number id' }); continue; }
      await voipline('/api/customer/order/' + orderId + '/number/' + numberId + '/reserve', 'PUT', {});
      const order = await voipline('/api/customer/order/' + orderId, 'GET');
      await voipline('/api/customer/order/' + orderId + '/submit', 'POST', {});
      const did = String(first.number || first.did || (order && order.number) || '').replace(/^\+/, '');
      result = { did, exchange: ex.town, pricingId, orderId, numberId };
      attempts.push({ town: ex.town, pricingId, stock: numbers.length, ordered: true });
      break;
    }
    if (result) break;
  } catch (e) {
    attempts.push({ town: ex.town, error: String(e.message || e) });
  }
}

if (result) {
  return [{ json: { ...d, ...result, did_obtained: true, attempts } }];
}
return [{ json: { ...d, did_obtained: false, all_exhausted: true, attempts } }];

// MOCKED 3CX SETUP - all 3CX API calls are mocked during build and return success.
// Live integration (Phase 1C) replaces this with real 3CX REST calls.
const d = $json;
const did = String(d.did || '').replace(/^\+/, '');
// Extension number auto-increments from 103. Live integration queries 3CX for the next free extension.
const extension = 103;
const mobileE164 = '+61' + String(d.mobile_number).replace(/^0/, '');

const threeCX = {
  mocked: true,
  success: true,
  steps: [
    { step: 'create_extension', extension: extension, ok: true },
    { step: 'set_identity', name: (d.prison_name || '') + ' (' + d.mobile_number + ')', email: d.customer_email || '', mobile: mobileE164, ok: true },
    { step: 'assign_did', did: did, ok: true },
    { step: 'configure', also_ring_my_mobile: true, no_answer_timeout_seconds: 15, forward_external_calls_to: 'Send Busy', voicemail_enabled: false, ok: true },
    { step: 'set_outbound_caller_id', outbound_caller_id: did, ok: true }
  ]
};

return [{ json: { ...d, did: did, threeCX_extension: extension, threeCX } }];

// Order confirmation SMS via ClickSend. Sender = PRISONCALL (alphanumeric, one-way).
const helpers = this.helpers;
const d = $json;
const to = '+61' + String(d.mobile_number).replace(/^0/, '');
const text = 'Welcome to Prisoncall! Your number ' + d.did + ' is now active for ' + d.prison_name + '. Calls from the prison will ring your mobile. Questions? Reply to this message.';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({
  method: 'POST',
  url: 'https://rest.clicksend.com/v3/sms/send',
  headers: { Authorization: auth, 'Content-Type': 'application/json' },
  body: { messages: [{ source: 'n8n', from: 'PRISONCALL', to: to, body: text }] },
  json: true
});
return [{ json: { ...d, clicksend_welcome: resp } }];

// PATH B - all exchanges out of stock. Submit a VoipLine Request Numbers order via the proxy.
// NOTE: confirm the exact VoipLine Request Numbers path and body shape at live integration.
const helpers = this.helpers;
const d = $json;
const PROXY_URL = 'https://workers.prisoncall.com.au/voipline-proxy';
const body = { quantity: 1, prefix: d.request_prefix, postcode: d.request_postcode };
let resp;
try {
  resp = await helpers.httpRequest({
    method: 'POST',
    url: PROXY_URL,
    headers: {
      'X-Proxy-Secret': $env.VOIPLINE_PROXY_SECRET,
      'X-VoipLine-Path': '/api/customer/numbers/request',
      'X-VoipLine-Method': 'POST',
      'Content-Type': 'application/json'
    },
    body: body,
    json: true
  });
} catch (e) { resp = { error: String(e.message || e) }; }
return [{ json: { ...d, path_b: true, request_numbers_submitted: body, request_numbers_response: resp } }];

// Notify owner that Path B is running and WF4 (email monitor) is now watching the inbox.
const helpers = this.helpers;
const d = $json;
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const text = 'PRISONCALL: All exchanges out of stock for ' + d.prison_name + ' (mobile ' + d.mobile_number + '). Request Numbers submitted to VoipLine. Monitoring voipline@ inbox for confirmation.';
const resp = await helpers.httpRequest({
  method: 'POST',
  url: 'https://rest.clicksend.com/v3/sms/send',
  headers: { Authorization: auth, 'Content-Type': 'application/json' },
  body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: $env.OWNER_MOBILE, body: text }] },
  json: true
});
return [{ json: { ...d, owner_monitoring_sms: resp } }];

// 24h elapsed with no Request Numbers confirmation. Alert owner with full subscriber details.
// At live integration, WF4 cancels/short-circuits this wait when a confirmation email arrives.
const helpers = this.helpers;
const d = $json;
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const text = 'PRISONCALL ALERT: No VoipLine number response in 24h. Prison: ' + d.prison_name + ', State: ' + d.prison_state + ', Mobile: ' + d.mobile_number + ', Sub: ' + d.stripe_subscription_id + '. Automation paused - manual follow-up required.';
const resp = await helpers.httpRequest({
  method: 'POST',
  url: 'https://rest.clicksend.com/v3/sms/send',
  headers: { Authorization: auth, 'Content-Type': 'application/json' },
  body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: $env.OWNER_MOBILE, body: text }] },
  json: true
});
return [{ json: { ...d, owner_alert_sms: resp, paused_for_manual_followup: true } }];
